import{_ as a,o,c as i,ag as t}from"./chunks/framework.B_-t2C-M.js";const p=JSON.parse('{"title":"Security & Validation","description":"","frontmatter":{},"headers":[],"relativePath":"api/security.md","filePath":"api/security.md"}'),s={name:"api/security.md"};function n(r,e,d,l,c,h){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="security-validation" tabindex="-1">Security &amp; Validation <a class="header-anchor" href="#security-validation" aria-label="Permalink to &quot;Security &amp; Validation&quot;">​</a></h1><p>LaraCommerce is built with enterprise-grade security in mind. This page details the built-in security features, middleware, and request validation mechanisms.</p><hr><h2 id="global-middleware" tabindex="-1">Global Middleware <a class="header-anchor" href="#global-middleware" aria-label="Permalink to &quot;Global Middleware&quot;">​</a></h2><p>Every API request passes through a series of global middlewares configured in <code>bootstrap/app.php</code>:</p><h3 id="_1-forcejsonresponse" tabindex="-1">1. <code>ForceJsonResponse</code> <a class="header-anchor" href="#_1-forcejsonresponse" aria-label="Permalink to &quot;1. `ForceJsonResponse`&quot;">​</a></h3><p>Automatically intercepts all requests (even those without the <code>Accept: application/json</code> header) and ensures that the API <em>always</em> returns a properly formatted JSON response. This prevents HTML error pages from leaking into client applications.</p><h3 id="_2-securityheaders" tabindex="-1">2. <code>SecurityHeaders</code> <a class="header-anchor" href="#_2-securityheaders" aria-label="Permalink to &quot;2. `SecurityHeaders`&quot;">​</a></h3><p>Adds crucial HTTP security headers to every response to protect against XSS, clickjacking, and other common web vulnerabilities:</p><ul><li><code>X-Frame-Options: DENY</code></li><li><code>X-XSS-Protection: 1; mode=block</code></li><li><code>X-Content-Type-Options: nosniff</code></li><li><code>Strict-Transport-Security: max-age=31536000; includeSubDomains</code></li><li><code>Referrer-Policy: strict-origin-when-cross-origin</code></li><li><code>Cache-Control: no-store, must-revalidate</code></li><li><code>Pragma: no-cache</code></li><li>Server identification headers (<code>X-Powered-By</code>, <code>Server</code>) are removed.</li></ul><h3 id="_3-rate-limiting-throttle" tabindex="-1">3. Rate Limiting (<code>throttle</code>) <a class="header-anchor" href="#_3-rate-limiting-throttle" aria-label="Permalink to &quot;3. Rate Limiting (`throttle`)&quot;">​</a></h3><p>LaraCommerce uses Redis-backed rate limiting in production to prevent brute-force and DDoS attacks.</p><ul><li><strong>Global API (<code>throttle:api</code>)</strong>: 60 requests per minute.</li><li><strong>Auth Routes (<code>throttle:auth</code>)</strong>: 10 requests per minute (Login, Register).</li><li><strong>Strict Routes (<code>throttle:strict</code>)</strong>: 5 requests per minute (Password reset, Returns).</li></ul><hr><h2 id="authentication-authorization" tabindex="-1">Authentication &amp; Authorization <a class="header-anchor" href="#authentication-authorization" aria-label="Permalink to &quot;Authentication &amp; Authorization&quot;">​</a></h2><h3 id="sanctum-tokens" tabindex="-1">Sanctum Tokens <a class="header-anchor" href="#sanctum-tokens" aria-label="Permalink to &quot;Sanctum Tokens&quot;">​</a></h3><p>The API uses <strong>Laravel Sanctum</strong> for stateful SPA authentication or token-based API authentication. We implement a <strong>dual-token system</strong>:</p><ol><li><strong>Access Token</strong>: Short-lived, used for all protected endpoints.</li><li><strong>Refresh Token</strong>: Long-lived, used to obtain a new access token without re-authenticating.</li></ol><h3 id="route-protection-aliases" tabindex="-1">Route Protection Aliases <a class="header-anchor" href="#route-protection-aliases" aria-label="Permalink to &quot;Route Protection Aliases&quot;">​</a></h3><p>Specific routes are protected using middleware aliases:</p><ul><li><code>check.active</code>: Ensures the authenticated user&#39;s account is not suspended (<code>is_active = true</code>). If suspended, returns a <code>403 Forbidden</code>.</li><li><code>email.verified</code>: Requires the user to have verified their email before accessing sensitive routes (e.g., placing an order, payments).</li></ul><h3 id="role-based-access-control-rbac" tabindex="-1">Role-Based Access Control (RBAC) <a class="header-anchor" href="#role-based-access-control-rbac" aria-label="Permalink to &quot;Role-Based Access Control (RBAC)&quot;">​</a></h3><p>We utilize <strong>Spatie Laravel Permission</strong> to handle complex authorization.</p><ul><li><strong>Roles</strong>: <code>customer</code>, <code>manager</code>, <code>admin</code>.</li><li><strong>Permissions</strong>: 57 granular permissions (e.g., <code>view orders</code>, <code>edit products</code>, <code>manage settings</code>).</li><li>Middleware applied to admin routes: <code>middleware([&#39;auth:sanctum&#39;, &#39;role:admin&#39;])</code>.</li></ul><hr><h2 id="validation-exception-handling" tabindex="-1">Validation &amp; Exception Handling <a class="header-anchor" href="#validation-exception-handling" aria-label="Permalink to &quot;Validation &amp; Exception Handling&quot;">​</a></h2><h3 id="form-requests" tabindex="-1">Form Requests <a class="header-anchor" href="#form-requests" aria-label="Permalink to &quot;Form Requests&quot;">​</a></h3><p>Incoming data is strictly validated using Laravel Form Requests (e.g., <code>StoreProductRequest</code>, <code>UpdateUserRequest</code>). Invalid data automatically triggers a <code>422 Unprocessable Entity</code> response with a structured error payload.</p><h3 id="model-validation-on-save-validatesonsave" tabindex="-1">Model Validation On Save (<code>ValidatesOnSave</code>) <a class="header-anchor" href="#model-validation-on-save-validatesonsave" aria-label="Permalink to &quot;Model Validation On Save (`ValidatesOnSave`)&quot;">​</a></h3><p>As a second layer of defense, a custom trait (<code>ValidatesOnSave</code>) is applied to Eloquent models. This ensures that even if data is modified programmatically outside of a controller, it must pass the model&#39;s validation rules before being saved to the database.</p><h3 id="centralized-exception-handler" tabindex="-1">Centralized Exception Handler <a class="header-anchor" href="#centralized-exception-handler" aria-label="Permalink to &quot;Centralized Exception Handler&quot;">​</a></h3><p>The API features a custom exception handler in <code>bootstrap/app.php</code> that intercepts all exceptions and normalizes them into a consistent JSON format.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Example of a normalized 403 response</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;message&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Forbidden. Insufficient permissions.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;FORBIDDEN&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Exceptions handled specifically:</p><ul><li><code>ValidationException</code> -&gt; <code>422</code></li><li><code>ModelValidationException</code> -&gt; <code>422</code></li><li><code>SpatieUnauthorizedException</code> -&gt; <code>403</code></li><li><code>AuthenticationException</code> -&gt; <code>401</code></li><li><code>NotFoundHttpException</code> -&gt; <code>404</code></li><li><code>MethodNotAllowedHttpException</code> -&gt; <code>405</code></li></ul><hr><h2 id="webhook-security" tabindex="-1">Webhook Security <a class="header-anchor" href="#webhook-security" aria-label="Permalink to &quot;Webhook Security&quot;">​</a></h2><h3 id="stripe-signature-verification" tabindex="-1">Stripe Signature Verification <a class="header-anchor" href="#stripe-signature-verification" aria-label="Permalink to &quot;Stripe Signature Verification&quot;">​</a></h3><p>All incoming Stripe webhooks are verified using <code>\\Stripe\\Webhook::constructEvent()</code> with the <code>STRIPE_WEBHOOK_SECRET</code> environment variable. If the secret is not configured, webhooks are rejected with a logged error. Invalid signatures return <code>400 Bad Request</code>.</p><h3 id="event-deduplication" tabindex="-1">Event Deduplication <a class="header-anchor" href="#event-deduplication" aria-label="Permalink to &quot;Event Deduplication&quot;">​</a></h3><p>Processed webhook events are cached for <strong>48 hours</strong> using the event ID as key. Duplicate events are silently acknowledged with <code>200 OK</code> to prevent double-processing (e.g., double refunds or duplicate order confirmations).</p><h3 id="ssrf-protection" tabindex="-1">SSRF Protection <a class="header-anchor" href="#ssrf-protection" aria-label="Permalink to &quot;SSRF Protection&quot;">​</a></h3><p>Custom webhook endpoint URLs (admin-configured) are validated against private/internal IP ranges:</p><ul><li><code>127.0.0.1</code>, <code>::1</code>, <code>0.0.0.0</code>, <code>localhost</code> are blocked</li><li>Private ranges (<code>10.x</code>, <code>172.16-31.x</code>, <code>192.168.x</code>) are blocked</li><li>Link-local (<code>169.254.x</code>) is blocked</li><li>DNS resolution is verified before accepting the URL</li></ul><hr><h2 id="data-protection" tabindex="-1">Data Protection <a class="header-anchor" href="#data-protection" aria-label="Permalink to &quot;Data Protection&quot;">​</a></h2><h3 id="api-logger-sanitization" tabindex="-1">API Logger Sanitization <a class="header-anchor" href="#api-logger-sanitization" aria-label="Permalink to &quot;API Logger Sanitization&quot;">​</a></h3><p>The <code>ApiLogger</code> middleware logs all API requests but sanitizes sensitive fields before storage: <code>password</code>, <code>password_confirmation</code>, <code>current_password</code>, <code>card_number</code>, <code>cvv</code>, <code>stripe_token</code>, <code>payment_method_id</code>, <code>secret</code>, <code>token</code>, <code>api_key</code>, <code>webhook_secret</code>, <code>authorization</code></p><h3 id="model-level-safeguards" tabindex="-1">Model-Level Safeguards <a class="header-anchor" href="#model-level-safeguards" aria-label="Permalink to &quot;Model-Level Safeguards&quot;">​</a></h3><ul><li>All models use <code>ValidatesOnSave</code> trait — data is validated even when modified programmatically</li><li>Sensitive fields hidden from JSON serialization via <code>$hidden</code>: passwords, tokens, Stripe IDs, IP addresses, cost prices</li><li>Stripe <code>client_secret</code> only exposed when payment status is <code>pending</code></li></ul><hr><h2 id="financial-safeguards" tabindex="-1">Financial Safeguards <a class="header-anchor" href="#financial-safeguards" aria-label="Permalink to &quot;Financial Safeguards&quot;">​</a></h2><ul><li><strong>Refund validation</strong>: Amount must be &gt; 0 and &lt;= original payment amount</li><li><strong>Wallet locking</strong>: Both <code>credit()</code> and <code>debit()</code> use <code>SELECT ... FOR UPDATE</code> pessimistic locks</li><li><strong>Inventory protection</strong>: <code>deduct()</code> throws <code>InsufficientStockException</code> if stock would go negative</li><li><strong>Payment idempotency</strong>: Each Stripe PaymentIntent uses a unique idempotency key</li><li><strong>Webhook deduplication</strong>: 48-hour cache prevents double-processing of payment events</li></ul>',53)])])}const g=a(s,[["render",n]]);export{p as __pageData,g as default};
